('tls-pki-and-certificates', 'TLS, PKI, and Certificates', 'Cybersecurity', 'Understanding certificate chains, TLS versions, trust stores, revocation, and operational certificate hygiene.'),
('vpns-zero-trust-and-remote-access', 'VPNs, Zero Trust, and Remote Access', 'Cybersecurity', 'Understanding secure remote access, tunneling, identity-aware access, and zero-trust concepts.'),
('vulnerability-assessment-and-prioritization', 'Vulnerability Assessment and Prioritization', 'Cybersecurity', 'Identify, validate, rate, and prioritize vulnerabilities using context and risk.'),
('web-api-and-application-security', 'Web, API, and Application Security', 'Cybersecurity', 'Applying Web, API, and Application Security means working with assets, threats, trust boundaries, preventive controls, detection, and response.'),
('web-application-penetration-testing', 'Web Application Penetration Testing', 'Cybersecurity', 'Applying authorized web testing methodology using safe labs and professional reporting.'),
('web-architecture-and-browser-security-model', 'Web Architecture and Browser Security Model', 'Cybersecurity', 'Understanding clients, servers, cookies, sessions, SOP, CORS, CSP, and browser trust boundaries.'),
('windows-and-active-directory', 'Windows and Active Directory', 'Cybersecurity', 'Competency in Windows and Active Directory requires attention to assets, threats, trust boundaries, preventive controls, detection, and response.'),
('windows-hardening', 'Windows Hardening', 'Cybersecurity', 'Applying patching, Defender, firewall, logging, account controls, and secure configuration baselines.'),
('windows-internals', 'Windows Internals', 'Cybersecurity', 'Understanding users, processes, registry, services, event logs, and security identifiers.'),
('wireless-security-testing', 'Wireless Security Testing', 'Cybersecurity', 'Understanding Wi-Fi security, enterprise wireless risks, and authorized testing constraints.');

UPDATE public.skill s SET category = ss.category, description = ss.description, is_active = true, updated_at = now() FROM seed_skill ss WHERE s.slug = ss.slug OR s.name = ss.name;
SELECT ss.name, ss.slug, ss.category, ss.description, true FROM seed_skill ss
WHERE NOT EXISTS (SELECT 1 FROM public.skill s WHERE s.slug = ss.slug OR s.name = ss.name);

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;

UPDATE public.learning_resource lr SET title = sr.title, resource_type = sr.resource_type, description = sr.description, provider = sr.provider, difficulty_level = sr.difficulty_level, language_code = 'en', verification_status = 'verified', updated_at = now() FROM (SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level FROM seed_resource ORDER BY url, resource_key) sr WHERE lr.url = sr.url;
SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified' FROM (SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level FROM seed_resource ORDER BY url, resource_key) sr WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    layout_role text NOT NULL,
    estimated_hours int,
    difficulty_level text,
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;

SELECT sn.node_id, m.roadmap_version_id, parent.node_id, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.order_index, sn.layout_role, sn.estimated_hours, sn.difficulty_level, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn CROSS JOIN seed_roadmap_map m LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (
    node_key text NOT NULL,
    skill_slug text NOT NULL,
    PRIMARY KEY (node_key, skill_slug)
) ON COMMIT DROP;


